// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// Set the Tasker Number after the task tree has been created.
	// The Task tree is created onInsert Order 50.
	// The default order set for this is 500.
	// It is set at 500 so customers can update any other field values they may want to use in the Tasker Number before this rule fires.
	// - The default setting for Tasker Number includes the Primary Assignee.  This rule fires after any rules associated with Primary Assignee fire.
	var taskerNM = new TaskerDisplayValueConfiguration();
	current.taskernumber = taskerNM.setTaskerNumber(current);

})(current, previous);
